INSERT INTO `racikan_pakan` VALUES (1,1,'Campuran Jagung Super','Starter','Racikan pakan starter berbahan lokal untuk ayam hari 1-21.',6500.00,19.50,'1. Timbang semua bahan\n2. Campur jagung dan dedak\n3. Tambahkan tepung ikan\n4. Masukkan konsentrat\n5. Aduk rata 10 menit',1,'2026-06-12 15:06:31','2026-07-05 19:17:54'),(2,1,'Formulasi Dedak Fermentasi','Finisher','Racikan pakan finisher berbasis dedak fermentasi H22-60.',5800.00,17.00,'1. Fermentasi dedak 24 jam\n2. Campur jagung dan dedak fermentasi\n3. Tambahkan SBM\n4. Aduk rata',1,'2026-06-12 15:06:31','2026-06-12 15:06:31'),(3,1,'Pakan Hemat Azolla','Semua','Racikan hemat berbahan azolla kering untuk semua fase.',4950.00,16.50,'1. Keringkan azolla 2-3 hari\n2. Giling hingga halus\n3. Campur dengan jagung dan dedak\n4. Tambahkan mineral mix',1,'2026-06-12 15:06:31','2026-06-12 15:06:31'),(4,1,'coba coba','Starter','uji aplikasi',5000.00,10.00,'1.masukkan',1,'2026-07-05 21:19:39','2026-07-05 21:19:39');
