DROP TABLE IF EXISTS `riwayat_prediksi`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `riwayat_prediksi` (
  `id_prediksi` int NOT NULL AUTO_INCREMENT,
  `id_peternak` int NOT NULL,
  `id_data_ternak` int NOT NULL,
  `id_model_rlb` int DEFAULT NULL,
  `id_model_rf` int DEFAULT NULL,
  `prediksi_pakan_kg` decimal(10,3) NOT NULL,
  `estimasi_berat_panen` decimal(8,2) DEFAULT NULL,
  `estimasi_populasi_panen` int DEFAULT NULL,
  `estimasi_bobot_total_kg` decimal(10,2) DEFAULT NULL,
  `deviasi_berat_persen` decimal(8,2) DEFAULT NULL,
  `status_nutrisi` enum('Normal','Peringatan_Ringan','Peringatan_Kritis') DEFAULT 'Normal',
  `tanggal_prediksi` datetime DEFAULT CURRENT_TIMESTAMP,
  `is_saved` tinyint(1) DEFAULT '1',
  `nama_batch` varchar(100) DEFAULT NULL,
  `tanggal_input` datetime DEFAULT CURRENT_TIMESTAMP,
  `hari` int DEFAULT NULL,
  `fase` varchar(50) DEFAULT NULL,
  `populasi_pagi` int DEFAULT NULL,
  `mortalitas_harian` int DEFAULT NULL,
  PRIMARY KEY (`id_prediksi`),
  KEY `id_data_ternak` (`id_data_ternak`),
  KEY `id_model_rlb` (`id_model_rlb`),
  KEY `id_model_rf` (`id_model_rf`),
  KEY `idx_riwayat_peternak` (`id_peternak`),
  KEY `idx_riwayat_tanggal` (`tanggal_prediksi`),
  CONSTRAINT `riwayat_prediksi_ibfk_1` FOREIGN KEY (`id_peternak`) REFERENCES `peternak` (`id_peternak`) ON DELETE CASCADE,
  CONSTRAINT `riwayat_prediksi_ibfk_2` FOREIGN KEY (`id_data_ternak`) REFERENCES `data_ternak` (`id_data_ternak`),
  CONSTRAINT `riwayat_prediksi_ibfk_3` FOREIGN KEY (`id_model_rlb`) REFERENCES `model_prediksi` (`id_model`),
  CONSTRAINT `riwayat_prediksi_ibfk_4` FOREIGN KEY (`id_model_rf`) REFERENCES `model_prediksi` (`id_model`)
) ENGINE=InnoDB AUTO_INCREMENT=35 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

